function r(t){const e=t.amount,n=Math.max(0,Math.floor((new Date().getTime()-new Date(t.dueDate).getTime())/(1e3*60*60*24))),u=n>0?500:0,o=n>0?10:0,a=5,s=e+u+o+a;return{baseAmount:e,lateFee:u,collectionFee:o,otherFees:a,totalAmount:s,daysOverdue:n}}function d(t){return t.filter(n=>n.status==="pending"||n.status==="overdue").reduce((n,u)=>{const o=r(u);return n+o.totalAmount},0)}function c(t){return t.filter(e=>e.status==="pending"||e.status==="overdue").sort((e,n)=>new Date(e.dueDate).getTime()-new Date(n.dueDate).getTime())}function i(t){return t.filter(e=>e.status==="pending"||e.status==="overdue").length}function m(t){const e=c(t);return e.length===0?0:r(e[0]).totalAmount}export{r as a,c as b,d as c,m as d,i as g};
